import{_ as e,o as d,c as i,ag as a}from"./chunks/framework.Vng7Hdlh.js";const p=JSON.parse('{"title":"3. 課金・サブスクリプション","description":"","frontmatter":{},"headers":[],"relativePath":"internal/03-billing.md","filePath":"internal/03-billing.md"}'),r={name:"internal/03-billing.md"};function l(o,t,h,n,s,c){return d(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="_3-課金・サブスクリプション" tabindex="-1">3. 課金・サブスクリプション <a class="header-anchor" href="#_3-課金・サブスクリプション" aria-label="Permalink to &quot;3. 課金・サブスクリプション&quot;">​</a></h1><p>POSLAはStripe Billingを使用したSaaS型のサブスクリプション課金モデルを採用しています。</p><h2 id="_3-1-プラン構成" tabindex="-1">3.1 プラン構成 <a class="header-anchor" href="#_3-1-プラン構成" aria-label="Permalink to &quot;3.1 プラン構成&quot;">​</a></h2><table tabindex="0"><thead><tr><th>プラン</th><th>月額目安</th><th>対象</th></tr></thead><tbody><tr><td>standard</td><td>¥10,000</td><td>店内飲食の基本運営</td></tr><tr><td>pro</td><td>¥20,000〜30,000</td><td>全チャネル＋経営管理</td></tr><tr><td>enterprise</td><td>¥50,000</td><td>多店舗統括</td></tr></tbody></table><h3 id="プラン別機能一覧" tabindex="-1">プラン別機能一覧 <a class="header-anchor" href="#プラン別機能一覧" aria-label="Permalink to &quot;プラン別機能一覧&quot;">​</a></h3><p><strong>standard（店内飲食の基本運営）：</strong></p><ul><li>セルフオーダー＋AIウェイター</li><li>ハンディPOS＋フロアマップ＋テーブル合流分割</li><li>KDS＋AI音声コマンド</li><li>基本レポート（売上日報）</li><li>オフライン検知＋マルチセッション制御</li></ul><p><strong>pro（全チャネル＋経営管理）：</strong></p><ul><li>standardの全機能に加えて：</li><li>在庫管理＋AI需要予測</li><li>高度レポート（回転率・客層・スタッフ評価・併売分析）＋監査ログ＋満足度評価</li><li>テイクアウト＋決済ゲートウェイ（Square/Stripe）</li><li>多言語対応</li><li>シフト管理</li></ul><p><strong>enterprise（多店舗統括）：</strong></p><ul><li>proの全機能に加えて：</li><li>HQメニュー一括配信</li><li>クロス店舗分析（ABC分析等）</li><li>統合シフトビュー</li><li>店舗間ヘルプ要請</li></ul><hr><h2 id="_3-2-stripe-billing設定" tabindex="-1">3.2 Stripe Billing設定 <a class="header-anchor" href="#_3-2-stripe-billing設定" aria-label="Permalink to &quot;3.2 Stripe Billing設定&quot;">​</a></h2><h3 id="事前準備" tabindex="-1">事前準備 <a class="header-anchor" href="#事前準備" aria-label="Permalink to &quot;事前準備&quot;">​</a></h3><p>POSLA管理画面の「API設定」タブで以下を設定します。</p><table tabindex="0"><thead><tr><th>キー</th><th>値</th><th>取得元</th></tr></thead><tbody><tr><td>stripe_secret_key</td><td>Stripeシークレットキー</td><td>Stripe Dashboard &gt; Developers &gt; API Keys</td></tr><tr><td>stripe_publishable_key</td><td>Stripe公開キー</td><td>同上</td></tr><tr><td>stripe_webhook_secret</td><td>Webhookシークレット</td><td>Stripe Dashboard &gt; Developers &gt; Webhooks</td></tr><tr><td>stripe_price_standard</td><td>Standardプランの価格ID</td><td>Stripe Dashboard &gt; Products</td></tr><tr><td>stripe_price_pro</td><td>Proプランの価格ID</td><td>同上</td></tr><tr><td>stripe_price_enterprise</td><td>Enterpriseプランの価格ID</td><td>同上</td></tr></tbody></table><h3 id="stripe上での商品作成手順" tabindex="-1">Stripe上での商品作成手順 <a class="header-anchor" href="#stripe上での商品作成手順" aria-label="Permalink to &quot;Stripe上での商品作成手順&quot;">​</a></h3><ol><li>Stripe Dashboardで商品を作成（例：「POSLA Standard」）</li><li>月額の価格を設定（例：¥10,000/月）</li><li>作成された価格ID（<code>price_xxx</code>）をPOSLA管理画面に入力</li></ol><h3 id="webhookの設定" tabindex="-1">Webhookの設定 <a class="header-anchor" href="#webhookの設定" aria-label="Permalink to &quot;Webhookの設定&quot;">​</a></h3><ol><li>Stripe Dashboardの「Developers」→「Webhooks」で新規エンドポイントを追加</li><li>URL：<code>https://あなたのドメイン/api/subscription/webhook.php</code></li><li>以下のイベントを選択： <ul><li><code>checkout.session.completed</code></li><li><code>customer.subscription.updated</code></li><li><code>customer.subscription.deleted</code></li><li><code>invoice.paid</code></li><li><code>invoice.payment_failed</code></li></ul></li><li>Webhookシークレット（<code>whsec_xxx</code>）をPOSLA管理画面に入力</li></ol><hr><h2 id="_3-3-サブスクリプションのライフサイクル" tabindex="-1">3.3 サブスクリプションのライフサイクル <a class="header-anchor" href="#_3-3-サブスクリプションのライフサイクル" aria-label="Permalink to &quot;3.3 サブスクリプションのライフサイクル&quot;">​</a></h2><h3 id="新規契約" tabindex="-1">新規契約 <a class="header-anchor" href="#新規契約" aria-label="Permalink to &quot;新規契約&quot;">​</a></h3><ol><li>テナントのオーナーがプラン選択画面にアクセスします</li><li>Stripe Checkoutセッションが作成されます</li><li>オーナーがStripeの決済フォームでクレジットカード情報を入力します</li><li>決済完了後、<code>checkout.session.completed</code> Webhookが発火します</li><li>POSLAがテナントのサブスクリプション情報を更新します</li></ol><h3 id="ステータスの遷移" tabindex="-1">ステータスの遷移 <a class="header-anchor" href="#ステータスの遷移" aria-label="Permalink to &quot;ステータスの遷移&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ステータス</th><th>意味</th></tr></thead><tbody><tr><td>none</td><td>サブスクリプション未設定</td></tr><tr><td>trialing</td><td>試用期間中</td></tr><tr><td>active</td><td>有効（支払い済み）</td></tr><tr><td>past_due</td><td>支払い延滞</td></tr><tr><td>canceled</td><td>キャンセル済み</td></tr></tbody></table><h3 id="webhookイベントの処理" tabindex="-1">Webhookイベントの処理 <a class="header-anchor" href="#webhookイベントの処理" aria-label="Permalink to &quot;Webhookイベントの処理&quot;">​</a></h3><table tabindex="0"><thead><tr><th>イベント</th><th>POSLAの処理</th></tr></thead><tbody><tr><td>checkout.session.completed</td><td>サブスクリプション作成、プラン設定</td></tr><tr><td>customer.subscription.updated</td><td>プラン変更の反映（アップグレード/ダウングレード）</td></tr><tr><td>customer.subscription.deleted</td><td>サブスクリプションのキャンセル処理</td></tr><tr><td>invoice.paid</td><td>支払い成功のログ記録</td></tr><tr><td>invoice.payment_failed</td><td>支払い失敗のログ記録</td></tr></tbody></table><h3 id="webhookの検証" tabindex="-1">Webhookの検証 <a class="header-anchor" href="#webhookの検証" aria-label="Permalink to &quot;Webhookの検証&quot;">​</a></h3><ul><li>HMAC-SHA256署名によるリクエスト検証</li><li>タイムスタンプチェック（5分以内のリクエストのみ有効）</li><li>検証失敗は400エラーを返却</li></ul><h3 id="イベントログ" tabindex="-1">イベントログ <a class="header-anchor" href="#イベントログ" aria-label="Permalink to &quot;イベントログ&quot;">​</a></h3><p>全Webhookイベントは<code>subscription_events</code>テーブルに記録されます。</p><table tabindex="0"><thead><tr><th>フィールド</th><th>説明</th></tr></thead><tbody><tr><td>event_id</td><td>UUID</td></tr><tr><td>tenant_id</td><td>対象テナント</td></tr><tr><td>event_type</td><td>Webhookイベントタイプ</td></tr><tr><td>stripe_event_id</td><td>StripeのイベントID</td></tr><tr><td>data</td><td>イベントデータ（JSON）</td></tr><tr><td>created_at</td><td>受信日時</td></tr></tbody></table><hr><h2 id="_3-4-プラン変更" tabindex="-1">3.4 プラン変更 <a class="header-anchor" href="#_3-4-プラン変更" aria-label="Permalink to &quot;3.4 プラン変更&quot;">​</a></h2><h3 id="アップグレード" tabindex="-1">アップグレード <a class="header-anchor" href="#アップグレード" aria-label="Permalink to &quot;アップグレード&quot;">​</a></h3><p>テナントがより上位のプランに変更する場合：</p><ol><li>Stripe上でサブスクリプションの価格IDを変更</li><li><code>customer.subscription.updated</code> Webhookが発火</li><li>POSLAがプランを更新し、<code>plan_features</code>に基づいて新機能が有効化</li></ol><h3 id="ダウングレード" tabindex="-1">ダウングレード <a class="header-anchor" href="#ダウングレード" aria-label="Permalink to &quot;ダウングレード&quot;">​</a></h3><p>テナントがより下位のプランに変更する場合：</p><ol><li>Stripe上でサブスクリプションの価格IDを変更</li><li>Webhookでプランが更新</li><li>上位プラン専用の機能のタブが管理ダッシュボードで非表示になる</li></ol><hr><h2 id="_3-5-テナントデータベースのサブスクリプション関連フィールド" tabindex="-1">3.5 テナントデータベースのサブスクリプション関連フィールド <a class="header-anchor" href="#_3-5-テナントデータベースのサブスクリプション関連フィールド" aria-label="Permalink to &quot;3.5 テナントデータベースのサブスクリプション関連フィールド&quot;">​</a></h2><table tabindex="0"><thead><tr><th>フィールド</th><th>型</th><th>説明</th></tr></thead><tbody><tr><td>stripe_customer_id</td><td>VARCHAR(50)</td><td>StripeのカスタマーID（cus_xxx）</td></tr><tr><td>stripe_subscription_id</td><td>VARCHAR(50)</td><td>StripeのサブスクリプションID（sub_xxx）</td></tr><tr><td>subscription_status</td><td>ENUM</td><td>none / active / past_due / canceled / trialing</td></tr><tr><td>current_period_end</td><td>DATETIME</td><td>現在の課金期間の終了日</td></tr></tbody></table>',44)])])}const u=e(r,[["render",l]]);export{p as __pageData,u as default};
